import re
import json
import sys
from typing import List, Dict, Any, Optional

class MdToSwaggerConverter:
    def __init__(self, md_content: str):
        self.md_content = md_content
        self.swagger = {
            "openapi": "3.0.0",
            "info": {
                "title": "Converted from Markdown",
                "version": "1.0.0",
                "description": "Auto-generated from MD documentation"
            },
            "servers": [],
            "paths": {},
            "components": {
                "schemas": {}
            }
        }
        self._extract_global_info()

    def _extract_global_info(self):
        # 提取 HOST
        host_match = re.search(r'\*\*HOST\*\*:\s*(\S+)', self.md_content)
        if host_match:
            host = host_match.group(1).strip()
            self.swagger["servers"] = [{"url": host}]
            print(f"[Info] 发现 Host: {host}")
        
        # 提取简介 (第一个 **简介**: 后面的内容)
        intro_match = re.search(r'\*\*简介\*\*:\s*(.+?)(?=\n|\*\*)', self.md_content)
        if intro_match:
            self.swagger["info"]["title"] = intro_match.group(1).strip()
            
        ver_match = re.search(r'\*\*Version\*\*:\s*(\S+)', self.md_content)
        if ver_match:
            self.swagger["info"]["version"] = ver_match.group(1).strip()

    def parse(self) -> Dict[str, Any]:
        # 核心策略改变：不再按标题分割，而是按 "**接口地址**" 分割
        # 这样即使标题格式乱了也能抓到接口
        split_pattern = r'(?=\*\*接口地址\*\*:)'
        sections = re.split(split_pattern, self.md_content)
        
        print(f"[Info] 文档被分割为 {len(sections)} 个部分")
        
        count = 0
        for i, section in enumerate(sections):
            if not section.strip():
                continue
            if "**接口地址**:" not in section:
                # 第一部分通常是文档头部，跳过
                if i == 0:
                    continue
                else:
                    print(f"[Warning] 第 {i} 部分缺少接口地址，跳过")
                    continue
            
            try:
                self._parse_section(section)
                count += 1
            except Exception as e:
                print(f"[Error] 解析第 {i} 部分失败: {e}")
                import traceback
                traceback.print_exc()
                
        print(f"[Success] 成功解析 {count} 个接口")
        return self.swagger

    def _parse_section(self, section: str):
        lines = section.split('\n')
        
        # 1. 提取元数据
        path = None
        method = "GET"
        req_type = "application/json"
        title = "Unknown Interface"
        
        # 尝试从上一段获取标题 (通常在接口地址上面一行或几行)
        # 简单策略：找 section 里第一个以 # 开头的行，或者紧挨着接口地址上面的非空行
        for idx, line in enumerate(lines):
            if "**接口地址**:" in line:
                match = re.search(r'`([^`]+)`', line)
                if match: 
                    path = match.group(1).strip()
                # 向上找标题
                for k in range(idx-1, -1, -1):
                    up_line = lines[k].strip()
                    if up_line.startswith('#'):
                        title = re.sub(r'^#+\s*', '', up_line).strip()
                        break
                    elif up_line and not up_line.startswith('|') and not up_line.startswith('**'):
                        title = up_line
                        break
                break
        
        if not path:
            print(f"[Warning] 未找到路径，跳过段落: {section[:50]}...")
            return

        # 2. 提取请求方式
        method_match = re.search(r'\*\*请求方式\*\*:\s*`([^`]+)`', section)
        if method_match:
            method = method_match.group(1).strip().upper()
            
        # 3. 提取请求数据类型
        req_type_match = re.search(r'\*\*请求数据类型\*\*:\s*`([^`]+)`', section)
        if req_type_match:
            req_type = req_type_match.group(1).strip()

        # 4. 解析表格
        request_params = self._extract_table_content(section, "**请求参数**:")
        response_params = self._extract_table_content(section, "**响应参数**:")
        
        # 5. 提取响应示例
        response_example = self._extract_example(section)

        # --- 构建 Swagger 对象 ---
        if path not in self.swagger["paths"]:
            self.swagger["paths"][path] = {}
        
        method_lower = method.lower()
        operation = {
            "summary": title,
            "tags": ["AutoGenerated"],
            "responses": {
                "200": {
                    "description": "Successful operation",
                    "content": {}
                }
            }
        }

        # 处理请求参数
        if request_params:
            if method in ["GET", "DELETE", "HEAD"]:
                operation["parameters"] = []
                for param in request_params:
                    if param["indent"] > 0: 
                        continue # GET 请求通常忽略嵌套，或者扁平化处理，这里简化忽略嵌套
                    operation["parameters"].append({
                        "name": param["name"],
                        "in": "query",
                        "required": "必填" in param.get("description", "") or "required" in param.get("description", "").lower(), # 简单判断
                        "schema": {"type": self._map_type(param["type"])},
                        "description": param.get("description", "")
                    })
            else:
                # POST/PUT: 构建 Body Schema
                schema_tree = self._build_schema_tree(request_params)
                operation["requestBody"] = {
                    "content": {
                        req_type: { "schema": schema_tree }
                    }
                }

        # 处理响应
        resp_content = {}
        if response_example:
            try:
                example_json = json.loads(response_example)
                resp_content["example"] = example_json
            except:
                resp_content["example"] = response_example
        
        if response_params:
            schema_tree = self._build_schema_tree(response_params)
            resp_content["schema"] = schema_tree
        elif not resp_content:
            resp_content["schema"] = {"type": "object"} # 默认
            
        operation["responses"]["200"]["content"]["application/json"] = resp_content

        self.swagger["paths"][path][method_lower] = operation
        print(f"[OK] 解析完成: {method} {path}")

    def _extract_example(self, section: str) -> str:
        # 查找 ```javascript 或 ```json 块
        pattern = r'```(?:javascript|json)?\s*(.*?)\s*```'
        match = re.search(pattern, section, re.DOTALL)
        if match:
            return match.group(1).strip()
        return ""

    def _extract_table_content(self, section: str, header_marker: str) -> List[Dict]:
        lines = section.split('\n')
        table_lines = []
        found_header = False
        table_started = False
        
        for line in lines:
            if header_marker in line:
                found_header = True
                continue
            
            if found_header:
                stripped = line.strip()
                if stripped.startswith('|'):
                    # 跳过表头分割线 |---|
                    if re.match(r'\|\s*[-:]+\s*\|', stripped):
                        continue
                    table_lines.append(line)
                    table_started = True
                else:
                    # 遇到非表格行，且表格已经开始，则结束
                    if table_started and stripped:
                        break
                    # 如果是空行，继续看后面有没有表格
                    if not stripped:
                        continue
        
        if not table_lines:
            return []
            
        return self._parse_table(table_lines)

    def _parse_table(self, lines: List[str]) -> List[Dict]:
        params = []
        # 第一行通常是表头，需要跳过吗？
        # 你的格式：| 参数名称 | 参数说明 | 类型 | schema |
        # 我们假设第一行是表头，从第二行开始是数据
        # 但为了保险，我们检查第一行是否包含 "参数名称" 或 "parameter"
        
        data_lines = lines
        if len(lines) > 0:
            first_row = lines[0].lower()
            if "参数名称" in first_row or "parameter" in first_row or "name" in first_row:
                data_lines = lines[1:] # 跳过表头

        for line in data_lines:
            cols = [c.strip() for c in line.split('|')]
            cols = [c for c in cols if c] # 去除空列
            
            if len(cols) < 2:
                continue
            
            # 适配不同列数：
            # 情况 A: | 名 | 说明 | 类型 | schema | (4列)
            # 情况 B: | 名 | 说明 | 类型 | (3列)
            name_raw = cols[0]
            desc = cols[1] if len(cols) > 1 else ""
            type_str = cols[2] if len(cols) > 2 else "string"
            
            # 计算缩进
            indent_level = name_raw.count('&emsp;')
            # 兼容半角空格缩进 (有时是 2 个或 4 个空格)
            if indent_level == 0:
                space_count = len(name_raw) - len(name_raw.lstrip(' '))
                if space_count > 0:
                    indent_level = space_count // 2 # 假设2个空格一级
            
            name = name_raw.replace('&emsp;', '').replace(' ', '').strip()
            
            # 清理类型
            clean_type = re.sub(r'\(.*\)', '', type_str).strip()
            
            params.append({
                "name": name,
                "description": desc,
                "type": clean_type,
                "indent": indent_level,
                "raw_type": type_str
            })
            
        return params

    def _build_schema_tree(self, params: List[Dict]) -> Dict[str, Any]:
        if not params:
            return {"type": "object"}
            
        root = {"type": "object", "properties": {}}
        # 栈结构：(节点对象, 该节点的缩进层级)
        stack = [(root, -1)] 
        
        for param in params:
            level = param["indent"]
            name = param["name"]
            p_type = self._map_type(param["type"])
            desc = param["description"]
            
            # 弹出栈顶，直到找到一个层级小于当前层级的父节点
            while len(stack) > 1 and stack[-1][1] >= level:
                stack.pop()
            
            parent_node, _ = stack[-1]
            
            if "properties" not in parent_node:
                parent_node["properties"] = {}
            
            new_node = {
                "type": p_type,
                "description": desc
            }
            
            # 处理数组
            if p_type == "array":
                new_node["items"] = {"type": "object", "properties": {}}
                # 数组的子元素应该在下一级，所以把 items 推入栈
                stack.append((new_node["items"], level))
            elif p_type == "object":
                # 对象属性，如果有子元素，推入栈
                stack.append((new_node, level))
            
            parent_node["properties"][name] = new_node
            
        return root

    def _map_type(self, md_type: str) -> str:
        if not md_type: return "string"
        t = md_type.lower()
        if "int" in t: return "integer"
        if "double" in t or "number" in t or "decimal" in t or "float" in t: return "number"
        if "bool" in t: return "boolean"
        if "array" in t or "list" in t or "[]" in t: return "array"
        if "object" in t or "map" in t or "json" in t: return "object"
        return "string"

def convert_file(input_md_path, output_json_path):
    try:
        with open(input_md_path, 'r', encoding='utf-8') as f:
            content = f.read()
    except FileNotFoundError:
        print(f"错误：找不到文件 {input_md_path}")
        return

    converter = MdToSwaggerConverter(content)
    result = converter.parse()
    
    if not result["paths"]:
        print("\n[严重警告] 解析结果为空！请检查 Markdown 格式是否包含 '**接口地址**:'")
        # 打印前500字符供调试
        # print("文档片段:", content[:500])
    
    with open(output_json_path, 'w', encoding='utf-8') as f:
        json.dump(result, f, indent=2, ensure_ascii=False)
    
    print(f"\n转换完成！输出文件：{output_json_path}")



if __name__ == "__main__":
    # 用法示例
    # python md_to_swagger.py input.md output.json
    convert_file("erp-server.md", "erp-server.json")
